SELECT evangelical_lutheran
FROM religious_affiliations
WHERE year = 2023;

SELECT year
FROM religious_affiliations
WHERE not_affiliated = (
  SELECT MAX(not_affiliated)
  FROM religious_affiliations
);

SELECT year
FROM religious_affiliations
WHERE CAST(REPLACE(evangelical_lutheran, '%', '') AS REAL) > 70;

SELECT year, not_affiliated 
FROM religious_affiliations
WHERE not_affiliated > '50';

SELECT COUNT(year) AS year_count
FROM religious_affiliations
WHERE year BETWEEN 2010 AND 2020;

SELECT DISTINCT year AS year_name
FROM religious_affiliations
ORDER BY year;

SELECT DISTINCT year_name
FROM years
ORDER BY year_name ASC;

SELECT year
FROM religious_affiliations
WHERE CAST(not_affiliated AS REAL) = (SELECT MAX(CAST(not_affiliated AS REAL)) FROM religious_affiliations);

SELECT year
FROM religious_affiliations
WHERE CAST(REPLACE(not_affiliated, '%', '') AS REAL) = (
  SELECT MAX(CAST(REPLACE(not_affiliated, '%', '') AS REAL))
  FROM religious_affiliations
);
